import { color as d3Color } from 'd3-color';

import { MARKER_STROKE_WIDTH } from '../../../constants.js';

function adjustBrightness(fillColor: string, brightness: string): string {
  const color = d3Color(fillColor);
  if (!color) {
    return fillColor;
  }

  const multiplier = parseFloat(brightness) / 100;
  const rgb = color.rgb();
  rgb.r = Math.min(255, Math.max(0, rgb.r * multiplier));
  rgb.g = Math.min(255, Math.max(0, rgb.g * multiplier));
  rgb.b = Math.min(255, Math.max(0, rgb.b * multiplier));
  return rgb.formatHex();
}

export function applyMarkerStyles(
  ctx: CanvasRenderingContext2D,
  opacity: number,
  brightness: string | undefined,
  fillColor: string,
  strokeColor: string,
) {
  const previousGlobalAlpha = ctx.globalAlpha;
  ctx.globalAlpha = opacity;

  const adjustedFillColor =
    brightness && brightness !== '100%'
      ? adjustBrightness(fillColor, brightness)
      : fillColor;

  ctx.fillStyle = adjustedFillColor;
  ctx.fill();
  ctx.globalAlpha = previousGlobalAlpha;

  ctx.lineWidth = MARKER_STROKE_WIDTH;
  ctx.strokeStyle = strokeColor;
  ctx.stroke();
}
